import React, { useState, useEffect } from 'react';
import Marquee from './Marquee';

function PlayButton() {
  const [songId, setSongId] = useState('No Song ID');

  const fetchNowPlayingData = () => {
    // Make an API request to fetch current song information
    fetch('http://your-azuracast-site.example.com/api/nowplaying/station_shortcode')
      .then(response => response.json())
      .then(data => {
        const currentSongId = data.now_playing.song.id || 'No Song ID';
        setSongId(currentSongId);
      })
      .catch(error => {
        console.error("Error fetching now playing data:", error);
      });
  };

  // Poll the API every 15 seconds (adjust this interval as needed)
  useEffect(() => {
    const intervalId = setInterval(fetchNowPlayingData, 15000);

    // Clean up the interval when component unmounts
    return () => {
      clearInterval(intervalId);
    };
  }, []);

  return (
    <div>
      {/* Your PlayButton component */}
      <button className="play-button">▶</button>
      <Marquee metadata={`Song ID: ${songId}`} />
    </div>
  );
}

export default PlayButton;
